<?php
declare(strict_types=1);
require_once __DIR__ . '/../includes/app-layout.php';
$wallet = beyond_nav_bootstrap('Beyond Media');
$videoCatalog = json_decode((string)@file_get_contents(__DIR__ . '/../beyond-tv/data/catalog.json'), true) ?: [];
foreach ($videoCatalog as &$mediaTitle) {
    $genre = strtolower((string)($mediaTitle['genre'] ?? ''));
    $channel = (string)($mediaTitle['channel_slug'] ?? '');
    if (($mediaTitle['type'] ?? '') === 'movie') $mediaTitle['_media_group'] = 'Movies';
    elseif ($channel === 'yugioh-tv' || str_contains($genre, 'anime')) $mediaTitle['_media_group'] = 'Anime';
    elseif (in_array($channel, ['bubble-guppies','preschool-francais'], true) || str_contains($genre, 'preschool')) $mediaTitle['_media_group'] = 'Kids';
    elseif ($channel === 'beyond-after-dark' || str_contains($genre, 'horror')) $mediaTitle['_media_group'] = 'After Dark';
    elseif ($channel === 'beyond-family' || str_contains($genre, 'family')) $mediaTitle['_media_group'] = 'Family';
    else $mediaTitle['_media_group'] = 'Shows';
}
unset($mediaTitle);
?>
