  <section class="catalogue-panel" id="video-catalogue"><header class="catalogue-heading"><div><span class="bos-kicker">Browse &amp; Explore</span><h2>The full Beyond video catalogue</h2><p>Discover shows, movies, anime, preschool favorites and After Dark collections without leaving Beyond Media.</p></div><a href="/beyond-tv/live-tv.php">View live guide <span>↗</span></a></header><div class="catalogue-tools"><label><span>Search the catalogue</span><input id="catalogueSearch" type="search" placeholder="Search titles, genres or descriptions…"></label><div class="catalogue-filters" role="group" aria-label="Filter video catalogue"><button class="active" type="button" data-catalogue-filter="all">All</button><?php foreach(['Movies','Shows','Anime','Kids','Family','After Dark'] as $group):?><button type="button" data-catalogue-filter="<?=e($group)?>"><?=e($group)?></button><?php endforeach;?></div></div><div class="catalogue-meta"><p id="catalogueCount"><?=count($videoCatalog)?> titles in Beyond Media</p><a href="/beyond-tv/browse.php">Open advanced TV browser →</a></div><div class="catalogue-grid" id="catalogueGrid"><?php foreach($videoCatalog as $index=>$item):$searchText=strtolower(implode(' ',[(string)($item['title']??''),(string)($item['subtitle']??''),(string)($item['genre']??''),(string)($item['description']??'')]));?><a class="catalogue-card" data-catalogue-index="<?=$index?>" data-catalogue-group="<?=e((string)$item['_media_group'])?>" data-catalogue-search="<?=e($searchText)?>" href="/beyond-tv/title.php?slug=<?=urlencode((string)$item['slug'])?>" <?=$index>=12?'hidden':''?>><?php if(!empty($item['thumbnail'])):?><img loading="lazy" src="<?=e((string)$item['thumbnail'])?>" alt=""><?php else:?><div class="catalogue-art" style="background:<?=e((string)($item['gradient']??'linear-gradient(135deg,#1c1535,#52285f)'))?>"><span><?=e((string)($item['icon']??'▶'))?></span></div><?php endif;?><div class="catalogue-copy"><span><?=e((string)$item['_media_group'])?> · <?=e((string)($item['rating']??'NR'))?></span><h3><?=e((string)$item['title'])?></h3><p><?=e((string)($item['subtitle']??$item['genre']??'Beyond TV'))?></p><small><?=($item['source_type']??'none')==='watchlist'?'Catalogue entry':'Play or explore'?> <b>→</b></small></div></a><?php endforeach;?></div><button class="catalogue-more" id="catalogueMore" type="button">Show all <?=count($videoCatalog)?> titles <span>↓</span></button><p class="catalogue-empty" id="catalogueEmpty" hidden>No catalogue titles match that search.</p></section>

