<script>
const q=s=>document.querySelector(s),esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[c]));
const catalogueCards=[...document.querySelectorAll('.catalogue-card')],catalogueSearch=q('#catalogueSearch'),catalogueCount=q('#catalogueCount'),catalogueMore=q('#catalogueMore'),catalogueEmpty=q('#catalogueEmpty');let catalogueFilter='all',catalogueExpanded=false;
function updateCatalogue(){const term=catalogueSearch.value.trim().toLowerCase(),filtered=term!==''||catalogueFilter!=='all';let matches=0,shown=0;catalogueCards.forEach(card=>{const match=(catalogueFilter==='all'||card.dataset.catalogueGroup===catalogueFilter)&&(!term||card.dataset.catalogueSearch.includes(term));if(match)matches++;const visible=match&&(filtered||catalogueExpanded||Number(card.dataset.catalogueIndex)<12);card.hidden=!visible;if(visible)shown++});catalogueCount.textContent=filtered?matches+' matching '+(matches===1?'title':'titles'):catalogueCards.length+' titles in Beyond Media';catalogueMore.hidden=filtered||catalogueCards.length<=12;catalogueMore.innerHTML=(catalogueExpanded?'Show featured titles <span>↑</span>':'Show all '+catalogueCards.length+' titles <span>↓</span>');catalogueEmpty.hidden=matches!==0}
document.querySelectorAll('[data-catalogue-filter]').forEach(button=>button.addEventListener('click',()=>{document.querySelectorAll('[data-catalogue-filter]').forEach(item=>item.classList.toggle('active',item===button));catalogueFilter=button.dataset.catalogueFilter;updateCatalogue()}));catalogueSearch.addEventListener('input',updateCatalogue);catalogueMore.addEventListener('click',()=>{catalogueExpanded=!catalogueExpanded;updateCatalogue();if(!catalogueExpanded)q('#video-catalogue').scrollIntoView({behavior:'smooth'})});updateCatalogue();
function youtubeId(value){try{const u=new URL(value);if(u.hostname==='youtu.be')return u.pathname.slice(1).split('/')[0];if(u.hostname.endsWith('youtube.com')){if(u.pathname.startsWith('/shorts/'))return u.pathname.split('/')[2];return u.searchParams.get('v')||''}}catch(e){}return ''}
q('#youtubeForm').addEventListener('submit',e=>{e.preventDefault();const id=youtubeId(q('#youtubeUrl').value.trim());if(!/^[A-Za-z0-9_-]{11}$/.test(id)){q('#youtubeStage').innerHTML='<p>Enter a valid YouTube video or Shorts URL.</p>';return}q('#youtubeStage').innerHTML='<iframe src="https://www.youtube-nocookie.com/embed/'+encodeURIComponent(id)+'?playsinline=1&rel=0" title="YouTube preview" allow="accelerometer; autoplay; encrypted-media; gyroscope; picture-in-picture; web-share" allowfullscreen></iframe>'});
let localObjectUrl='';q('#localFile').addEventListener('change',e=>{const f=e.target.files&&e.target.files[0];if(!f)return;if(localObjectUrl)URL.revokeObjectURL(localObjectUrl);localObjectUrl=URL.createObjectURL(f);const tag=f.type.startsWith('audio/')?'audio':f.type.startsWith('video/')?'video':'';if(!tag){q('#localStage').innerHTML='<p>This file type cannot be previewed.</p>';return}q('#localStage').innerHTML='<'+tag+' controls playsinline src="'+localObjectUrl+'"></'+tag+'>';q('#localActions').innerHTML='<a class="bos-btn secondary" download="'+esc(f.name)+'" href="'+localObjectUrl+'">Save original file</a><p>'+esc(f.name)+' · '+formatBytes(f.size)+'</p>'});
function formatBytes(n){if(!Number.isFinite(Number(n)))return '';const units=['B','KB','MB','GB'];let i=0;while(n>=1024&&i<3){n/=1024;i++}return n.toFixed(i?1:0)+' '+units[i]}
q('#openForm').addEventListener('submit',async e=>{e.preventDefault();const query=q('#openQuery').value.trim(),type=q('#openType').value;q('#searchStatus').textContent='Searching licensed Archive records…';q('#resultGrid').innerHTML='';try{const r=await fetch('/beyond-media/api/search.php?q='+encodeURIComponent(query)+'&type='+encodeURIComponent(type));const d=await r.json();if(!d.ok)throw new Error(d.error||'Search failed');q('#searchStatus').textContent=d.results.length+' open-media results. Verify each source license before reuse.';q('#resultGrid').innerHTML=d.results.map(x=>'<article class="result-card"><img loading="lazy" src="'+esc(x.thumbnail)+'" alt=""><div><span>'+esc(x.type)+' '+esc(x.year)+'</span><h3>'+esc(x.title)+'</h3><p>'+esc(x.creator)+'</p><div class="result-actions"><button type="button" data-files="'+esc(x.id)+'">Authorized files</button><a target="_blank" rel="noopener" href="'+esc(x.source_url)+'">Review source ↗</a></div></div></article>').join('')||'<p>No licensed results found. Try a broader search.</p>'}catch(err){q('#searchStatus').textContent=err.message||'Search is temporarily unavailable.'}});
q('#resultGrid').addEventListener('click',async e=>{const b=e.target.closest('[data-files]');if(!b)return;b.disabled=true;b.textContent='Checking license…';try{const r=await fetch('/beyond-media/api/files.php?id='+encodeURIComponent(b.dataset.files));const d=await r.json();if(!d.ok)throw new Error(d.error||'Unable to load files');const content=q('#fileDialogContent');content.innerHTML='<span class="bos-kicker">Authorized source files</span><h2>Available MP3 / MP4 files</h2>'+(d.authorized?'<p>These files are exposed only because the source metadata advertises a Creative Commons or public-domain license. Confirm the exact terms at the source.</p><div class="file-list">'+d.files.map(f=>'<a target="_blank" rel="noopener" href="'+esc(f.url)+'" download><b>'+esc(f.name)+'</b><span>'+esc(f.format)+' · '+formatBytes(f.size)+'</span></a>').join('')+'</div>':'<p>This item does not provide clear open-license metadata, so Beyond Media has disabled downloads.</p>')+'<a class="source-review" target="_blank" rel="noopener" href="'+esc(d.source_url)+'">Review item and license on Internet Archive ↗</a>';q('#fileDialog').showModal()}catch(err){alert(err.message)}finally{b.disabled=false;b.textContent='Authorized files'}});
q('.dialog-close').addEventListener('click',()=>q('#fileDialog').close());q('#fileDialog').addEventListener('click',e=>{if(e.target===q('#fileDialog'))q('#fileDialog').close()});
</script>
