background:none}.local-tool #localActions{display:flex;flex-wrap:wrap;gap:12px;align-items:center;margin-top:12px}.search-panel{grid-template-columns:1fr}.result-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:14px}.result-card{overflow:hidden;border:1px solid var(--bos-line);border-radius:18px;background:#090c21}.result-card img{width:100%;aspect-ratio:16/10;object-fit:cover;background:#10152c}.result-card>div{padding:16px}.result-card span{color:#53efd1;font-size:.78rem;text-transform:uppercase}.result-card h3{margin:7px 0}.result-card p{color:var(--bos-muted)}.result-actions{display:flex;gap:10px;align-items:center}.result-actions button,.result-actions a,.source-review{border:0;background:none;padding:0;color:#aa91ff;font:inherit;font-weight:900;text-decoration:none;cursor:pointer}dialog{width:min(760px,calc(100% - 28px));max-height:85vh;overflow:auto;padding:28px;border:1px solid rgba(255,255,255,.2);border-radius:24px;background:#10132c;color:white}dialog::backdrop{background:rgba(2,4,13,.78);backdrop-filter:blur(8px)}.dialog-close{float:right;border:0;background:none;color:white;font-size:2rem;cursor:pointer}.file-list{display:grid;gap:9px;margin:20px 0}.file-list a{display:flex;justify-content:space-between;gap:12px;padding:12px;border-radius:12px;background:rgba(255,255,255,.07);color:white;text-decoration:none}.file-list span{color:#aab0cf;font-size:.8rem}.source-review{display:inline-block;margin-top:8px}html[data-theme="sunset"] .media-page{background:radial-gradient(circle at 80% 0,rgba(255,111,97,.26),transparent 30%),linear-gradient(180deg,#32113d,#1d102b 48%,#0d1021)}html[data-theme="sunset"] .media-panel,html[data-theme="sunset"] .media-links a{background:rgba(62,23,58,.74)}
@media(max-width:880px){.media-panel{grid-template-columns:1fr}.result-grid{grid-template-columns:repeat(2,1fr)}}@media(max-width:620px){.media-main{width:min(100% - 18px,1320px)}.media-hero{padding:28px 18px}.media-links,.result-grid{grid-template-columns:1fr}.youtube-tool form,.search-form{grid-template-columns:1fr}.media-panel{padding:20px 15px}.preview-stage,.preview-stage iframe,.preview-stage video{min-height:230px}.file-list a{display:grid}}
