;font-style:normal}.media-orbit>i span{font-weight:950}.orbit-one{left:3%;top:45%;color:#61efda;animation:orbitFloat 3s ease-in-out infinite}.orbit-two{right:10%;top:13%;color:#d47cff;animation:orbitFloat 3.4s ease-in-out infinite reverse}.orbit-three{right:2%;bottom:18%;color:#66cfff;animation:orbitFloat 2.7s ease-in-out infinite}.media-wave{position:absolute;left:16%;right:16%;bottom:16%;height:34px;background:linear-gradient(90deg,transparent,#4fe4e4 20%,#d15cff 50%,#4fe4e4 80%,transparent);clip-path:polygon(0 48%,10% 48%,14% 18%,19% 80%,25% 35%,31% 63%,38% 48%,100% 48%,100% 53%,38% 53%,31% 68%,25% 40%,19% 85%,14% 23%,10% 53%,0 53%);opacity:.8}.media-links a{position:relative;min-height:120px;overflow:hidden;transition:transform .2s ease,border-color .2s ease,box-shadow .2s ease}.media-links a:hover{transform:translateY(-4px);border-color:rgba(96,228,231,.48);box-shadow:0 18px 36px rgba(0,0,0,.25)}.media-links i{margin-left:auto;color:#72ebdc;font-style:normal;font-size:.78rem;font-weight:950;white-space:nowrap}.media-jump{position:sticky;top:74px;z-index:20;display:flex;gap:6px;overflow:auto;margin:14px 0;padding:7px;border:1px solid var(--bos-line);border-radius:16px;background:rgba(8,10,29,.86);box-shadow:0 12px 35px rgba(0,0,0,.25);backdrop-filter:blur(18px)}.media-jump a{padding:10px 14px;border-radius:11px;color:#b9bfd8;text-decoration:none;font-size:.84rem;font-weight:900;white-space:nowrap}.media-jump a:first-child{background:linear-gradient(135deg,#6e4ee0,#21cfd5);color:white}.catalogue-panel{margin:18px 0;padding:clamp(24px,4vw,42px);border:1px solid var(--bos-line);border-radius:28px;background:linear-gradient(145deg,rgba(19,20,51,.93),rgba(9,12,34,.88));scroll-margin-top:145px}.catalogue-heading{display:flex;justify-content:space-between;gap:30px;align-items:end}.catalogue-heading h2{margin:.3rem 0;font-size:clamp(2rem,5vw,3.5rem);letter-spacing:-.04em}.catalogue-heading p{max-width:680px;color:var(--bos-muted);line-height:1.6}.catalogue-heading>a,.ca